import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { adminAPI } from '../services/api';
import { useAdminAuth } from '../context/AuthContext';

// ── Chart: Vertical Bar ───────────────────────────────────────────────────────
const BarChart = ({ data = [], color = '#dc3545', height = 140 }) => {
  if (!data.length || data.every(d => d.value === 0))
    return <div className="text-center text-muted py-4 small">No data yet</div>;
  const max = Math.max(...data.map(d => d.value), 1);
  return (
    <div style={{ overflowX:'auto' }}>
      <div className="d-flex align-items-end gap-1" style={{ height, minWidth: data.length * 36 }}>
        {data.map((d, i) => {
          const barH = Math.max((d.value / max) * (height - 30), d.value > 0 ? 6 : 0);
          return (
            <div key={i} className="d-flex flex-column align-items-center flex-grow-1" style={{ minWidth:32 }}>
              <div className="text-muted text-center fw-bold" style={{ fontSize:'0.6rem', marginBottom:2 }}>
                {d.value > 0 ? d.value : ''}
              </div>
              <div style={{ width:'100%', borderRadius:'4px 4px 0 0', background: d.color || color,
                            height: barH, opacity:0.88, transition:'height 0.5s ease' }}
                title={`${d.label}: ${d.value}`} />
              <div className="text-muted text-center text-truncate w-100" style={{ fontSize:'0.58rem', marginTop:3, maxWidth:60 }}>
                {d.label}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

// ── Chart: Donut ──────────────────────────────────────────────────────────────
const DonutChart = ({ segments = [], size = 150, label = 'Total' }) => {
  const total = segments.reduce((s, x) => s + x.value, 0);
  if (!total) return <div className="text-center text-muted py-4 small">No data yet</div>;
  const cx = size/2, cy = size/2, r = size*0.36, inner = size*0.20;
  let angle = -Math.PI / 2;
  const arcs = segments.map(seg => {
    const frac = seg.value / total;
    const sweep = frac * 2 * Math.PI;
    const x1 = cx + r * Math.cos(angle), y1 = cy + r * Math.sin(angle);
    angle += sweep;
    const x2 = cx + r * Math.cos(angle), y2 = cy + r * Math.sin(angle);
    const path = frac >= 1
      ? `M ${cx} ${cy-r} A ${r} ${r} 0 1 1 ${cx-0.001} ${cy-r} Z`
      : `M ${x1} ${y1} A ${r} ${r} 0 ${frac > 0.5 ? 1 : 0} 1 ${x2} ${y2} L ${cx} ${cy} Z`;
    return { ...seg, path, frac };
  });
  return (
    <div className="d-flex align-items-center gap-3 flex-wrap justify-content-center">
      <svg width={size} height={size} style={{ flexShrink:0 }}>
        {arcs.filter(a => a.frac > 0).map((a, i) => (
          <path key={i} d={a.path} fill={a.color} stroke="#fff" strokeWidth={2.5}>
            <title>{a.label}: {a.value}</title>
          </path>
        ))}
        <circle cx={cx} cy={cy} r={inner} fill="#fff" />
        <text x={cx} y={cy-6}  textAnchor="middle" fontSize={10} fill="#888">{label}</text>
        <text x={cx} y={cy+10} textAnchor="middle" fontSize={14} fontWeight="bold" fill="#333">{total.toLocaleString()}</text>
      </svg>
      <div className="d-flex flex-column gap-2">
        {segments.map((s, i) => (
          <div key={i} className="d-flex align-items-center gap-2 small">
            <div style={{ width:11, height:11, borderRadius:3, background:s.color, flexShrink:0 }} />
            <span className="text-muted">{s.label}</span>
            <span className="fw-bold">{s.value.toLocaleString()}</span>
            {total > 0 && <span className="text-muted">({Math.round(s.value/total*100)}%)</span>}
          </div>
        ))}
      </div>
    </div>
  );
};

// ── Chart: Sparkline ─────────────────────────────────────────────────────────
const Sparkline = ({ values = [], color = '#198754', height = 70, labels = [] }) => {
  if (!values.length || values.every(v => v === 0))
    return <div className="text-center text-muted py-3 small">No activity yet</div>;
  const max = Math.max(...values, 1);
  const w = 300, h = height - 14, pad = 8;
  const pts = values.map((v, i) => {
    const x = pad + (i / Math.max(values.length-1, 1)) * (w - pad*2);
    const y = h - pad - (v/max)*(h - pad*2);
    return [x, y];
  });
  const polyline = pts.map(p => p.join(',')).join(' ');
  const area = `M ${pts[0][0]} ${h} ` + pts.map(p => `L ${p[0]} ${p[1]}`).join(' ') + ` L ${pts[pts.length-1][0]} ${h} Z`;
  return (
    <div>
      <svg width="100%" viewBox={`0 0 ${w} ${h}`} preserveAspectRatio="none" style={{ height:h, display:'block' }}>
        <defs>
          <linearGradient id="sg" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor={color} stopOpacity="0.25"/>
            <stop offset="100%" stopColor={color} stopOpacity="0.02"/>
          </linearGradient>
        </defs>
        <path d={area} fill="url(#sg)" />
        <polyline points={polyline} fill="none" stroke={color} strokeWidth={2.5} strokeLinecap="round" strokeLinejoin="round" />
        {pts.map(([x, y], i) => (
          <circle key={i} cx={x} cy={y} r={3.5} fill={color} stroke="#fff" strokeWidth={1.5}>
            <title>{labels[i] || i}: {values[i]}</title>
          </circle>
        ))}
      </svg>
      {labels.length > 0 && (
        <div className="d-flex justify-content-between mt-1">
          {labels.map((l,i) => (
            <div key={i} className="text-muted text-center" style={{ fontSize:'0.58rem', flex:1 }}>{l}</div>
          ))}
        </div>
      )}
    </div>
  );
};

// ── KPI Card ──────────────────────────────────────────────────────────────────
const KpiCard = ({ icon, label, value, bg, color, border, link, sub }) => (
  <Link to={link} className="text-decoration-none">
    <div className="card border-0 shadow-sm h-100 rounded-3"
      style={{ background:bg, borderLeft:`4px solid ${border}`, transition:'transform 0.15s, box-shadow 0.15s' }}
      onMouseEnter={e => { e.currentTarget.style.transform='translateY(-3px)'; e.currentTarget.style.boxShadow='0 6px 20px rgba(0,0,0,0.1)'; }}
      onMouseLeave={e => { e.currentTarget.style.transform='none'; e.currentTarget.style.boxShadow=''; }}>
      <div className="card-body text-center py-3 px-2">
        <div style={{ fontSize:'1.8rem' }}>{icon}</div>
        <div className="fw-bold" style={{ fontSize:'1.5rem', lineHeight:1.2, color }}>{value ?? '—'}</div>
        <div className="fw-semibold" style={{ fontSize:'0.72rem', color, opacity:0.8 }}>{label}</div>
        {sub && <div className="mt-1" style={{ fontSize:'0.65rem', color:'#888' }}>{sub}</div>}
      </div>
    </div>
  </Link>
);

// ── Chart card wrapper ────────────────────────────────────────────────────────
const ChartCard = ({ title, link, linkLabel, linkColor, children, accentColor }) => (
  <div className="card border-0 shadow-sm h-100 rounded-3 overflow-hidden">
    <div style={{ height:3, background:accentColor || '#1a1a1a' }}/>
    <div className="card-header fw-bold small d-flex justify-content-between align-items-center"
      style={{ background:'#1a1a1a', color:'#fff', border:0 }}>
      <span>{title}</span>
      {link && (
        <Link to={link} className="badge text-decoration-none rounded-pill px-2"
          style={{ background: linkColor||'#555', color:'#fff', fontSize:'0.62rem' }}>
          {linkLabel}
        </Link>
      )}
    </div>
    <div className="card-body">
      {children}
    </div>
  </div>
);

// ── Main Dashboard ────────────────────────────────────────────────────────────
const AdminDashboard = () => {
  const { admin } = useAdminAuth();
  const [overview, setOverview] = useState(null);
  const [users,    setUsers]    = useState([]);
  const [products, setProducts] = useState([]);
  const [events,   setEvents]   = useState([]);
  const [loading,  setLoading]  = useState(true);
  const [error,    setError]    = useState('');

  useEffect(() => {
    Promise.all([
      adminAPI.overview(), adminAPI.users(), adminAPI.products(), adminAPI.recentEvents(),
    ]).then(([ov, us, pr, ev]) => {
      setOverview(ov.data); setUsers(us.data||[]); setProducts(pr.data||[]); setEvents(ev.data||[]);
      setLoading(false);
    }).catch(err => { setError(err.response?.data?.message||'Failed to load'); setLoading(false); });
  }, []);

  if (loading) return (
    <div style={{ background:'#f1f3f6', minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center' }}>
      <div className="text-center">
        <div className="spinner-border" style={{ width:'3rem', height:'3rem', color:'#dc3545' }}/>
        <p className="mt-3 text-muted">Loading dashboard...</p>
      </div>
    </div>
  );
  if (error) return <div className="alert alert-danger m-3">{error}</div>;

  // ── Derived data ──────────────────────────────────────────────────────────
  const eventDonut = [
    { label:'Views',     value: events.filter(e=>e.actionType==='product_viewed').length, color:'#2874f0' },
    { label:'Cart Adds', value: events.filter(e=>e.actionType==='add_to_cart').length,    color:'#ff9f00' },
    { label:'Purchases', value: events.filter(e=>e.actionType==='purchase').length,       color:'#26a541' },
  ];

  const topProducts = [...products]
    .sort((a,b) => b.totalPurchases - a.totalPurchases).slice(0,8)
    .map(p => ({ label: p.productName.split(' ').slice(0,2).join(' '), value: p.totalPurchases }));

  const catColors = { Phones:'#2874f0', Laptops:'#26a541', Gadgets:'#ff9f00', Accessories:'#e91e63' };
  const catRevMap = {};
  products.forEach(p => { catRevMap[p.category] = (catRevMap[p.category]||0) + (p.totalRevenue||0); });
  const catDonut = Object.entries(catRevMap).map(([cat, rev]) => ({
    label:cat, value:Math.round(rev/1000), color:catColors[cat]||'#9e9e9e'
  }));

  const statusBars = [
    { label:'🔥 Hot',    value:products.filter(p=>p.status==='hot').length,    color:'#dc3545' },
    { label:'📈 Normal', value:products.filter(p=>p.status==='normal').length, color:'#26a541' },
    { label:'📉 Slow',   value:products.filter(p=>p.status==='slow').length,   color:'#ff9f00' },
    { label:'💀 Dead',   value:products.filter(p=>p.status==='dead').length,   color:'#9e9e9e' },
  ];

  const now = Date.now();
  const hourBuckets = Array(8).fill(0);
  events.forEach(e => {
    const hrs = (now - new Date(e.createdAt).getTime()) / 3600000;
    if (hrs < 8) hourBuckets[Math.min(7, Math.floor(hrs))]++;
  });
  const sparkValues = [...hourBuckets].reverse();
  const sparkLabels = ['7h','6h','5h','4h','3h','2h','1h','Now'];

  const userBars = [...users]
    .sort((a,b)=>(b.stats?.purchases||0)-(a.stats?.purchases||0)).slice(0,6)
    .map(u => ({ label:u.name?.split(' ')[0]||u.email?.split('@')[0], value:u.stats?.purchases||0 }));

  const revBars = Object.entries(catRevMap)
    .map(([cat,rev]) => ({ label:cat, value:Math.round(rev/1000), color:catColors[cat]||'#9e9e9e' }))
    .sort((a,b)=>b.value-a.value);

  const kpis = [
    { label:'Total Users',  value:overview?.totalUsers,    icon:'👥', bg:'#e8f4fd', color:'#1565c0', border:'#2874f0', link:'/users',       sub:`${users.filter(u=>u.stats?.purchases>0).length} purchased` },
    { label:'Total Events', value:overview?.totalEvents,   icon:'📋', bg:'#e8f5e9', color:'#1b5e20', border:'#26a541', link:'/events',      sub:`${eventDonut[0].value} views` },
    { label:'Purchases',    value:overview?.totalPurchases,icon:'💳', bg:'#fff8e1', color:'#e65100', border:'#ff9f00', link:'/tracker',     sub:`${products.filter(p=>p.status==='hot').length} hot products` },
    { label:'Revenue',      value:`₹${((overview?.totalRevenue||0)/1000).toFixed(1)}K`, icon:'💰', bg:'#fce4ec', color:'#880e4f', border:'#e91e63', link:'/sales-board', sub:'Total across all products' },
  ];

  return (
    <div style={{ background:'#f1f3f6', minHeight:'100vh', padding:'1rem' }}>

      {/* ── Welcome banner ── */}
      <div className="card border-0 shadow-sm mb-3 rounded-3 overflow-hidden d-none d-md-block">
        <div style={{ height:5, background:'linear-gradient(90deg,#1a0000,#dc3545,#ff6b6b,#1a0000)' }}/>
        <div className="card-body p-4">
          <div className="row align-items-center g-2">
            <div className="col-md-8">
              <div className="d-flex align-items-center gap-3 mb-2">
                <div className="rounded-circle d-flex align-items-center justify-content-center fw-bold text-white flex-shrink-0"
                  style={{ width:52, height:52, fontSize:'1.4rem', background:'linear-gradient(135deg,#dc3545,#c62828)' }}>
                  {admin?.name?.charAt(0).toUpperCase()}
                </div>
                <div>
                  <h5 className="fw-bold mb-0" style={{ color:'#212121' }}>⚙️ Admin Dashboard</h5>
                  <div className="text-muted small">Welcome back, <strong>{admin?.name}</strong></div>
                </div>
              </div>
              <div className="d-flex gap-2 flex-wrap">
                <span className="badge rounded-pill px-3 py-1" style={{ background:'#fce4ec', color:'#c62828', fontSize:'0.72rem' }}>
                  👥 {overview?.totalUsers} Users
                </span>
                <span className="badge rounded-pill px-3 py-1" style={{ background:'#e8f5e9', color:'#1b5e20', fontSize:'0.72rem' }}>
                  📋 {overview?.totalEvents} Events
                </span>
                <span className="badge rounded-pill px-3 py-1" style={{ background:'#e8f4fd', color:'#1565c0', fontSize:'0.72rem' }}>
                  📦 {products.length} Products Tracked
                </span>
              </div>
            </div>
            <div className="col-md-4 text-end d-none d-lg-block">
              <div style={{ fontSize:'3.5rem' }}>⚙️</div>
            </div>
          </div>
        </div>
      </div>

      {/* ── KPI Row ── */}
      <div className="row g-2 g-md-3 mb-3">
        {kpis.map((k,i) => (
          <div key={i} className="col-6 col-md-3">
            <KpiCard {...k} />
          </div>
        ))}
      </div>

      {/* ── Top seller banner ── */}
      {overview?.topProduct && (
        <div className="rounded-3 px-4 py-3 mb-3 d-flex align-items-center gap-3 flex-wrap shadow-sm"
          style={{ background:'#fff8e1', border:'1px solid #ffe082' }}>
          <span style={{ fontSize:'2rem' }}>{overview.topProduct.emoji||'📦'}</span>
          <div className="flex-grow-1">
            <span className="fw-bold" style={{ color:'#e65100' }}>🏆 Top Seller: </span>
            <span className="fw-semibold" style={{ color:'#212121' }}>{overview.topProduct.productName}</span>
          </div>
          <div className="d-flex gap-2 flex-wrap">
            <span className="badge rounded-pill px-3 py-1" style={{ background:'#fff3cd', color:'#856404', fontSize:'0.75rem' }}>
              {overview.topProduct.totalPurchases} purchases
            </span>
            <span className="badge rounded-pill px-3 py-1" style={{ background:'#e8f5e9', color:'#1b5e20', fontSize:'0.75rem' }}>
              ₹{(overview.topProduct.totalRevenue||0).toLocaleString('en-IN')}
            </span>
          </div>
        </div>
      )}

      {/* ── Row 1: Event donut + Top products bar ── */}
      <div className="row g-3 mb-3">
        <div className="col-12 col-md-5">
          <ChartCard title="📊 Events Breakdown" link="/events" linkLabel="View All" accentColor="#2874f0">
            <div className="d-flex align-items-center justify-content-center py-2">
              <DonutChart segments={eventDonut} size={160} label="Events" />
            </div>
          </ChartCard>
        </div>
        <div className="col-12 col-md-7">
          <ChartCard title="🏆 Top 8 Products by Purchases" link="/sales-board" linkLabel="Full Board" linkColor="#ff9f00" accentColor="#dc3545">
            <BarChart data={topProducts} color="#dc3545" height={150} />
          </ChartCard>
        </div>
      </div>

      {/* ── Row 2: Revenue donut + Status bar ── */}
      <div className="row g-3 mb-3">
        <div className="col-12 col-md-5">
          <ChartCard title="💰 Revenue by Category (₹K)" accentColor="#26a541">
            <div className="d-flex align-items-center justify-content-center py-2">
              <DonutChart segments={catDonut} size={160} label="₹K" />
            </div>
          </ChartCard>
        </div>
        <div className="col-12 col-md-7">
          <ChartCard title="📦 Product Performance Status" accentColor="#ff9f00">
            <BarChart data={statusBars} height={120} />
            <div className="d-flex gap-3 flex-wrap mt-2 justify-content-center">
              {statusBars.map((s,i) => (
                <div key={i} className="d-flex align-items-center gap-1 small">
                  <div style={{ width:10, height:10, borderRadius:2, background:s.color }} />
                  <span className="text-muted">{s.label}</span>
                  <strong>{s.value}</strong>
                </div>
              ))}
            </div>
          </ChartCard>
        </div>
      </div>

      {/* ── Row 3: Sparkline + Revenue bars ── */}
      <div className="row g-3 mb-3">
        <div className="col-12 col-md-6">
          <ChartCard title="📈 Event Activity — Last 8 Hours" accentColor="#e91e63">
            <Sparkline values={sparkValues} color="#e91e63" height={100} labels={sparkLabels} />
            <div className="text-center text-muted mt-1" style={{ fontSize:'0.7rem' }}>
              Total in window: <strong>{sparkValues.reduce((s,v)=>s+v,0)}</strong> events
            </div>
          </ChartCard>
        </div>
        <div className="col-12 col-md-6">
          <ChartCard title="💹 Revenue by Category" accentColor="#9c27b0">
            <BarChart data={revBars} height={120} />
            <div className="text-center text-muted mt-1" style={{ fontSize:'0.7rem' }}>Values in ₹ thousands</div>
          </ChartCard>
        </div>
      </div>

      {/* ── Row 4: User bar + Leaderboard ── */}
      <div className="row g-3 mb-3">
        <div className="col-12 col-md-5">
          <ChartCard title="👥 Top Users by Purchases" accentColor="#6f42c1">
            <BarChart data={userBars} color="#6f42c1" height={130} />
          </ChartCard>
        </div>
        <div className="col-12 col-md-7">
          <div className="card border-0 shadow-sm h-100 rounded-3 overflow-hidden">
            <div style={{ height:3, background:'linear-gradient(90deg,#ff9f00,#ff6d00)' }}/>
            <div className="card-header fw-bold small d-flex justify-content-between align-items-center"
              style={{ background:'#1a1a1a', color:'#fff', border:0 }}>
              <span>🏅 Top 5 Users — Leaderboard</span>
              <Link to="/users" className="badge rounded-pill px-2 text-decoration-none"
                style={{ background:'#555', color:'#fff', fontSize:'0.62rem' }}>All Users</Link>
            </div>
            <div className="card-body p-0">
              <div className="table-responsive">
                <table className="table table-sm mb-0 align-middle">
                  <thead style={{ background:'#f5f5f5' }}>
                    <tr>
                      <th style={{ width:44, border:0, color:'#555', fontSize:'0.78rem' }}>#</th>
                      <th style={{ border:0, color:'#555', fontSize:'0.78rem' }}>User</th>
                      <th className="text-center" style={{ width:70, border:0, color:'#555', fontSize:'0.78rem' }}>Buys</th>
                      <th className="text-end" style={{ width:120, border:0, color:'#555', fontSize:'0.78rem' }}>Revenue</th>
                    </tr>
                  </thead>
                  <tbody>
                    {[...users].sort((a,b)=>(b.stats?.purchases||0)-(a.stats?.purchases||0)).slice(0,5).map((u,i) => (
                      <tr key={i} style={{ borderTop:'1px solid #f0f0f0' }}>
                        <td className="text-center fw-bold" style={{ fontSize:'1.1rem', border:0 }}>
                          {i===0?'🥇':i===1?'🥈':i===2?'🥉':<span className="text-muted small">#{i+1}</span>}
                        </td>
                        <td style={{ border:0 }}>
                          <div className="small fw-semibold" style={{ color:'#212121' }}>{u.name}</div>
                          <div className="text-muted" style={{ fontSize:'0.65rem' }}>{u.email}</div>
                        </td>
                        <td className="text-center" style={{ border:0 }}>
                          <span className="badge rounded-pill px-2"
                            style={{ background:'#e8f5e9', color:'#1b5e20', fontSize:'0.75rem' }}>
                            {u.stats?.purchases||0}
                          </span>
                        </td>
                        <td className="text-end fw-bold small" style={{ color:'#26a541', border:0 }}>
                          ₹{(u.stats?.revenue||0).toLocaleString('en-IN')}
                        </td>
                      </tr>
                    ))}
                    {users.length===0 && (
                      <tr><td colSpan={4} className="text-center text-muted py-3 small" style={{ border:0 }}>No users yet</td></tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* ── Quick nav ── */}
      <h6 className="fw-bold mb-2" style={{ color:'#555', fontSize:'0.78rem', textTransform:'uppercase', letterSpacing:'1px' }}>
        Quick Access
      </h6>
      <div className="row g-2">
        {[
          { to:'/users',       icon:'👥', label:'All Users',        desc:'User list & purchase history', bg:'#e8f4fd', border:'#2874f0', color:'#1565c0' },
          { to:'/sales-board', icon:'🏆', label:'Sales Board',      desc:'Products ranked by sales',     bg:'#fff8e1', border:'#ff9f00', color:'#e65100' },
          { to:'/tracker',     icon:'🛒', label:'Purchase Tracker', desc:'Product performance metrics',  bg:'#e8f5e9', border:'#26a541', color:'#1b5e20' },
          { to:'/events',      icon:'📋', label:'Recent Events',    desc:'Live event feed all users',    bg:'#fce4ec', border:'#e91e63', color:'#880e4f' },
        ].map((n,i) => (
          <div key={i} className="col-6 col-md-3">
            <Link to={n.to} className="text-decoration-none">
              <div className="card border-0 shadow-sm text-center h-100 rounded-3 overflow-hidden"
                style={{ transition:'transform 0.15s, box-shadow 0.15s', border:`1px solid ${n.border}22` }}
                onMouseEnter={e => { e.currentTarget.style.transform='translateY(-3px)'; e.currentTarget.style.boxShadow='0 6px 20px rgba(0,0,0,0.1)'; }}
                onMouseLeave={e => { e.currentTarget.style.transform='none'; e.currentTarget.style.boxShadow=''; }}>
                <div style={{ height:3, background:`linear-gradient(90deg,${n.border},${n.color})` }}/>
                <div className="card-body py-3" style={{ background:n.bg }}>
                  <div style={{ fontSize:'2rem' }}>{n.icon}</div>
                  <h6 className="fw-bold mt-2 mb-1 small" style={{ color:'#212121' }}>{n.label}</h6>
                  <p className="mb-0 fw-semibold" style={{ fontSize:'0.68rem', color:n.color }}>{n.desc}</p>
                </div>
              </div>
            </Link>
          </div>
        ))}
      </div>

    </div>
  );
};

export default AdminDashboard;
